        count -= input;
    }

    function overflowlocalonly(uint256 input) public {
        uint res = count + input;
    }

    function overflowmulocalonly(uint256 input) public {
        uint res = count * input;
    }

    function underflowlocalonly(uint256 input) public {
        uint res = count - input;
    }
}

