    }

    function changeOwner(address newOwner) onlyowner {
        owner = newOwner;
    }

    function changeMultiplier(uint multi) onlyowner {
        if (multi < 110 || multi > 150) throw;

        multiplier = multi;
    }

    function changeFee(uint newFee) onlyowner {
        if (fee > 5) throw;
        fee = newFee;
    }

    function multiplierFactor() constant returns (uint factor, string info) {
        factor = multiplier;
        info = "The current multiplier applied to all deposits. Min 110%, max 150%.";
    }

    function currentFee() constant returns (uint feePercentage, string info) {
        feePercentage = fee;
        info = "The fee percentage applied to all deposits. It can change to speed payouts (max 5%).";
    }

    function totalEntries() constant returns (uint count, string info) {
        count = entries.length;
        info = "The number of deposits.";
    }

    function userStats(
        address user
    ) constant returns (uint deposits, uint payouts, string info) {
        if (users[user].id != address(0x0)) {
            deposits = users[user].deposits;
            payouts = users[user].payoutsReceived;
            info = "Users stats: total deposits, payouts received.";
        }
    }

    function entryDetails(
        uint index
    ) constant returns (address user, uint payout, bool paid, string info) {
        if (index < entries.length) {
            user = entries[index].entryAddress;
            payout = entries[index].payout / 1 finney;
            paid = entries[index].paid;
            info = "Entry info: user address, expected payout in Finneys, payout status.";
        }
    }
}
```
Output:
- Access Control: Present
Explanation: The `onlyowner` modifier restricts access to the `changeOwner`, `changeMultiplier`, and `changeFee` functions to the contract owner. However, the `LuckyDoubler()` constructor initializes the `owner` variable with the sender of the transaction. This means that if an attacker sends Ether to the contract, they can become the owner and change the contract's settings. To mitigate this, the constructor should check if the owner is already set or explicitly set the owner to a predefined address.

- Arithmetic: Absent
Explanation: The code does not contain any arithmetic operations that could lead to overflows or underflows.

- Bad Randomness: Absent
Explanation: The randomness is derived from `block.blockhash(block.number - 1)` and modified with a constant factor. While this method is not ideal, it is not predictable and does not use any private seed.

- Denial Of Service: Absent
Explanation: There are no functions that could be exploited to cause a denial of service by consuming excessive resources.

- Front Running: Absent
Explanation: The contract does not rely on transaction order or reveal secrets that could be exploited by front-running.

- Reentrancy: Absent
Explanation: The contract functions do not make external calls that could be exploited for reentrancy attacks. They directly send Ether to addresses and do not perform any external calls.

- Short Addresses: Absent
Explanation: The contract does not process external addresses in a way that could be exploited by sending malformed addresses.

- Time Manipulation: Absent
Explanation: The contract uses `block.number - 1` to obtain a block hash, but it does not depend on block timestamps that miners can influence.

- Unchecked Low Level Calls: Absent
Explanation: The contract uses `send` to transfer Ether, which does not involve unchecked low-level calls.

