        if (block.timestamp < lastInvestmentTimestamp + ONE_MINUTE) throw;

        lastInvestor.send(jackpot);
        owner.send(this.balance - 1 ether);

        lastInvestor = 0;
        jackpot = 1 ether;
        lastInvestmentTimestamp = 0;
    }
}

